(* no_rw_check *)
reg ram [7:0];
integer word_addr = AD*2;
always @(posedge CLK) begin
  if (WE) begin
    for (integer i = 0; i < 2; i=i+1) ram[word_addr+i] <= DI[i];
  end
  for (integer i = 0; i < 2; i=i+1) begin
    DO[i] <= ram[word_addr+i];
  end
end

for (integer i = 0; i < 2; i=i+1) begin
  ram[word_addr+i] <= DI[i];
end
